323	/**
324	 * Validate aider-specific settings.
325	 * Throws on invalid types to catch config errors at load time.
326	 */
327	export function validateAiderSettings(
328	  aider: unknown,
329	): AiderSettings | undefined {
330	  if (aider == null) return undefined;
331	  if (typeof aider !== "object" || Array.isArray(aider)) {
332	    throw new Error("settings.run.aider must be an object");
333	  }
334	  const obj = aider as Record<string, unknown>;
335	  if (obj.model !== undefined && typeof obj.model !== "string") {
336	    throw new Error("settings.run.aider.model must be a string");
337	  }
338	  if (obj.editFormat !== undefined && typeof obj.editFormat !== "string") {
339	    throw new Error("settings.run.aider.editFormat must be a string");
340	  }
341	  if (obj.extraArgs !== undefined) {
342	    if (
343	      !Array.isArray(obj.extraArgs) ||
344	      !obj.extraArgs.every((a) => typeof a === "string")
345	    ) {
346	      throw new Error(
347	        "settings.run.aider.extraArgs must be an array of strings",
348	      );
349	    }
350	  }
351	  return obj as unknown as AiderSettings;
352	}
353	
354	/**
355	 * Get the current project settings
356	 *
357	 * Returns default settings if no settings file exists.
358	 */
359	export async function getSettings(): Promise<SequantSettings> {
360	  if (!(await fileExists(SETTINGS_PATH))) {
361	    return DEFAULT_SETTINGS;
362	  }
363	
364	  try {
365	    const content = await readFile(SETTINGS_PATH);
366	    const parsed = JSON.parse(content) as Partial<SequantSettings>;
367	
368	    // Validate aider settings if present
369	    const aiderSettings = validateAiderSettings(
370	      (parsed.run as Record<string, unknown> | undefined)?.aider,
371	    );
372	
373	    // Merge with defaults to ensure all fields exist
374	    return {
375	      version: parsed.version ?? DEFAULT_SETTINGS.version,
376	      run: {
377	        ...DEFAULT_SETTINGS.run,
378	        ...parsed.run,
379	        ...(aiderSettings !== undefined ? { aider: aiderSettings } : {}),
380	      },
381	      agents: {
382	        ...DEFAULT_AGENT_SETTINGS,
383	        ...parsed.agents,
384	      },
385	      scopeAssessment: {
386	        ...DEFAULT_SCOPE_ASSESSMENT_SETTINGS,
387	        ...parsed.scopeAssessment,
388	        trivialThresholds: {
389	          ...DEFAULT_SCOPE_ASSESSMENT_SETTINGS.trivialThresholds,
390	          ...parsed.scopeAssessment?.trivialThresholds,
391	        },
392	        thresholds: {
393	          ...DEFAULT_SCOPE_ASSESSMENT_SETTINGS.thresholds,
394	          ...parsed.scopeAssessment?.thresholds,
395	        },
396	      },
397	      qa: {
398	        ...DEFAULT_QA_SETTINGS,
399	        ...parsed.qa,
400	      },
401	    };
402	  } catch {
403	    return DEFAULT_SETTINGS;
404	  }
405	}
406	
407	/**
408	 * Save project settings
409	 */
410	export async function saveSettings(settings: SequantSettings): Promise<void> {
411	  await ensureDir(dirname(SETTINGS_PATH));
412	  await writeFile(SETTINGS_PATH, JSON.stringify(settings, null, 2));
413	}
414	
415	/**
416	 * Check if settings file exists
417	 */
418	export async function settingsExist(): Promise<boolean> {
419	  return fileExists(SETTINGS_PATH);
420	}
421	
422	/**
423	 * Create default settings file
424	 */
425	export async function createDefaultSettings(): Promise<void> {
426	  await saveSettings(DEFAULT_SETTINGS);
427	}
